mapper.select:
SELECT ch.id, ch.user_id as userId, IFNULL(u.username, CONCAT('用户', ch.user_id)) as userName, ch.user_question as userQuestion, ch.answer_source as answerSource, ch.ai_answer as aiAnswer, ch.rating, DATE_FORMAT(ch.create_time, '%Y-%m-%d %H:%i:%s') as createTime FROM chat_history ch LEFT JOIN user u ON ch.user_id = u.id
AND (ch.user_question LIKE CONCAT('%', #{keyword}, '%') OR ch.ai_answer LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND ch.answer_source = #{answerSource}
AND ch.rating IS NULL
AND ch.rating = #{rating}
ORDER BY ch.create_time ASC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM chat_history ch LEFT JOIN user u ON ch.user_id = u.id
AND (ch.user_question LIKE CONCAT('%', #{keyword}, '%') OR ch.ai_answer LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND ch.answer_source = #{answerSource}
AND ch.rating IS NULL
AND ch.rating = #{rating}
